const body = $input.first().json.body;
const message = body.message;

// Extract call details
const call = message.call || {};
const artifact = message.artifact || {};
const analysis = message.analysis || {};

// Build transcript from messages
const messages = artifact.messages || [];
const transcript = messages
  .filter(m => m.role === 'user' || m.role === 'bot' || m.role === 'assistant')
  .map(m => {
    const role = m.role === 'user' ? 'Customer' : 'Agent';
    return `${role}: ${m.message || m.content || ''}`;
  })
  .filter(line => line.length > 10)
  .join('\n');

// Calculate duration
const startedAt = call.createdAt || call.startedAt || null;
const endedAt = message.endedAt || call.endedAt || null;
let durationSeconds = 0;
if (startedAt && endedAt) {
  durationSeconds = Math.round((new Date(endedAt) - new Date(startedAt)) / 1000);
}

// Check if call was escalated 
// 1. Look for the tool call 'submit_escalation' anywhere in the raw message string
// 2. Look for the system confirmation message about the form being submitted
const wasEscalated = messages.some(m => {
  const content = JSON.stringify(m).toLowerCase();
  return (
    content.includes('submit_escalation') || 
    (m.role === 'system' && content.includes('submitted the escalation form'))
  );
});

// Get summary if available
const summary = analysis.summary || '';

return [{
  json: {
    call_id: call.id || 'unknown',
    status: message.endedReason || 'completed',
    started_at: startedAt,
    ended_at: endedAt,
    duration_seconds: durationSeconds,
    transcript: transcript,
    summary: summary,
    escalated: wasEscalated,
    escalation_reason: wasEscalated ? 'Escalation triggered during call' : null
  }
}];

